// 把 items 陣列拆成逐項
const items = $input.first().json.body?.items || $input.first().json.items || [];
return items.map(item => ({ json: item }));

// =============================================
// 完整逐字稿生成流程（單項）
// TikHub 下載 URL → 下載影片 → Gemini 上傳 → Gemini 生成 → 寫回 DB
// =============================================

const TIKHUB_BASE = $env.TIKHUB_API_BASE_URL || 'https://api.tikhub.io';
const TIKHUB_KEY = $env.TIKHUB_API_KEY || '';
const GEMINI_KEY = $env.GEMINI_API_KEY || '';
const GEMINI_MODEL = 'gemini-2.5-flash';
const SQL_WEBHOOK = 'https://lokokk2002ai.zeabur.app/webhook/supabase-sql';

const item = $input.first().json;
const { queue_item_id, platform, video_id, video_url, title, author_name } = item;

// 工具函式：執行 SQL
async function runSQL(sql) {
  const res = await fetch(SQL_WEBHOOK, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ sql }),
  });
  return res.json();
}

// 工具函式：更新狀態
async function updateStatus(status, scriptRaw = null, timecodes = null) {
  const sets = [`status = '${status}'`];
  if (scriptRaw !== null) {
    sets.push(`script_raw = '${scriptRaw.replace(/'/g, "''")}'`);
  }
  if (timecodes !== null) {
    sets.push(`script_timecodes = '${JSON.stringify(timecodes).replace(/'/g, "''")}'::jsonb`);
  }
  if (status === 'completed') {
    sets.push(`script_generated_at = NOW()`);
  }
  await runSQL(
    `UPDATE viral_benchmark.shoot_queue SET ${sets.join(', ')} WHERE id = '${queue_item_id}'`
  );
}

try {
  // === Step 1: TikHub 取得無水印下載 URL ===
  let downloadUrl = null;

  if (platform === 'douyin' || platform === 'tiktok') {
    const apiPath = platform === 'douyin'
      ? '/api/v1/douyin/app/v3/fetch_one_video'
      : '/api/v1/tiktok/app/v3/fetch_one_video';

    const tikRes = await fetch(
      `${TIKHUB_BASE}${apiPath}?aweme_id=${video_id}`,
      {
        headers: {
          Authorization: `Bearer ${TIKHUB_KEY}`,
          Accept: 'application/json',
        },
      }
    );

    if (tikRes.ok) {
      const tikJson = await tikRes.json();
      if (tikJson.code === 200) {
        const aweme = tikJson.data?.aweme_detail || tikJson.data;
        downloadUrl =
          aweme?.video?.play_addr?.url_list?.[0] ||
          aweme?.video?.play_addr_h264?.url_list?.[0] ||
          aweme?.video?.play_addr_lowbr?.url_list?.[0] ||
          aweme?.video?.download_addr?.url_list?.[0] ||
          null;
      }
    }
  }

  if (!downloadUrl) {
    const platformName = platform === 'xiaohongshu' ? '小紅書' :
      platform === 'douyin' ? '抖音' :
      platform === 'tiktok' ? 'TikTok' : platform;
    const errMsg = `無法取得影片下載連結（${platformName}）`;
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // === Step 2: 下載影片 ===
  const videoRes = await fetch(downloadUrl, {
    headers: {
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
      Referer: 'https://www.douyin.com/',
    },
    redirect: 'follow',
  });

  if (!videoRes.ok) {
    const errMsg = '影片下載失敗，URL 可能已過期';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  const videoBuffer = await videoRes.arrayBuffer();
  const contentType = videoRes.headers.get('content-type') || 'video/mp4';
  const mimeType = contentType.includes('video') ? contentType : 'video/mp4';

  if (videoBuffer.byteLength < 10240) {
    const errMsg = '下載的影片檔案太小（< 10KB）';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // === Step 3: Gemini Files API 上傳 ===
  const numBytes = videoBuffer.byteLength;
  const displayName = `viral_${platform}_${video_id}`;

  // 3a: 開始上傳
  const startRes = await fetch(
    `https://generativelanguage.googleapis.com/upload/v1beta/files?key=${GEMINI_KEY}`,
    {
      method: 'POST',
      headers: {
        'X-Goog-Upload-Protocol': 'resumable',
        'X-Goog-Upload-Command': 'start',
        'X-Goog-Upload-Header-Content-Length': String(numBytes),
        'X-Goog-Upload-Header-Content-Type': mimeType,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ file: { display_name: displayName } }),
    }
  );

  if (!startRes.ok) {
    const err = await startRes.text();
    const errMsg = `Gemini 上傳啟動失敗: ${startRes.status}`;
    await updateStatus('failed', `${errMsg} ${err.substring(0, 200)}`);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  const uploadUrl = startRes.headers.get('x-goog-upload-url');
  if (!uploadUrl) {
    const errMsg = 'Gemini 上傳: 缺少 upload URL';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // 3b: 上傳影片資料
  const uploadRes = await fetch(uploadUrl, {
    method: 'POST',
    headers: {
      'X-Goog-Upload-Command': 'upload, finalize',
      'X-Goog-Upload-Offset': '0',
      'Content-Length': String(numBytes),
    },
    body: videoBuffer,
  });

  if (!uploadRes.ok) {
    const err = await uploadRes.text();
    const errMsg = `Gemini 上傳失敗: ${uploadRes.status}`;
    await updateStatus('failed', `${errMsg} ${err.substring(0, 200)}`);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  const uploadJson = await uploadRes.json();
  const fileUri = uploadJson?.file?.uri;
  const fileName = uploadJson?.file?.name;

  if (!fileUri || !fileName) {
    const errMsg = 'Gemini 上傳: 缺少 file URI';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // 3c: 等待影片處理完成
  let fileReady = false;
  for (let i = 0; i < 30; i++) {
    await new Promise(r => setTimeout(r, 3000));
    const statusRes = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/${fileName}?key=${GEMINI_KEY}`
    );
    if (!statusRes.ok) continue;
    const statusJson = await statusRes.json();
    if (statusJson.state === 'ACTIVE') { fileReady = true; break; }
    if (statusJson.state === 'FAILED') {
      const errMsg = 'Gemini 影片處理失敗';
      await updateStatus('failed', errMsg);
      return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
    }
  }

  if (!fileReady) {
    const errMsg = 'Gemini 影片處理超時（90秒）';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // === Step 4: Gemini 多模態生成逐字稿 ===
  const PROMPT = `你是一位專業的影片逐字稿轉錄員。\n\n## 任務\n請仔細觀看並聆聽這支影片，產出 **1:1 完全還原** 的逐字稿。\n\n## 嚴格要求\n1. **dialogue 欄位必須是影片中實際說出的每一句話**，一字不漏、一字不改、不要潤飾、不要改寫、不要摘要\n2. 如果影片中有背景音樂但沒有人說話，dialogue 填「（無對話）」\n3. 如果影片中有畫面文字（字卡、字幕），在 scene 中完整記錄\n4. scene 欄位描述你「實際看到的畫面」，不是你推測的\n5. note 欄位記錄該片段的拍攝手法或特殊效果（轉場、濾鏡、特效文字等）\n6. **必須使用繁體中文輸出**（即使原始影片是簡體中文或其他語言，也要轉為繁體中文）\n7. 時間碼必須精準對應影片的實際時間軸\n\n## 輸出格式\n直接輸出 JSON 陣列，不要用 markdown code block 包裝，不要加任何說明文字：\n[\n  {\n    "timecode": "00:00-00:03",\n    "scene": "實際看到的畫面描述",\n    "dialogue": "影片中實際說出的原話（繁體中文）",\n    "note": "拍攝手法備註"\n  }\n]`;

  const geminiRes = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/${GEMINI_MODEL}:generateContent?key=${GEMINI_KEY}`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [
          { file_data: { mime_type: mimeType, file_uri: fileUri } },
          { text: PROMPT },
        ]}],
        generationConfig: { temperature: 0.2, maxOutputTokens: 8192 },
      }),
    }
  );

  if (!geminiRes.ok) {
    const errText = await geminiRes.text();
    const errMsg = `Gemini API 錯誤: ${geminiRes.status}`;
    await updateStatus('failed', `${errMsg} ${errText.substring(0, 300)}`);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  const geminiJson = await geminiRes.json();
  const raw = geminiJson.candidates?.[0]?.content?.parts?.[0]?.text || '';

  if (!raw) {
    const errMsg = 'Gemini 回傳空白內容';
    await updateStatus('failed', errMsg);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // === Step 5: 解析 JSON 逐字稿 ===
  let timecodes = [];
  try {
    const match = raw.match(/\[[\s\S]*\]/);
    if (match) timecodes = JSON.parse(match[0]);
  } catch {}
  if (timecodes.length === 0) {
    try {
      const match = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (match) timecodes = JSON.parse(match[1].trim());
    } catch {}
  }
  if (Array.isArray(timecodes) && timecodes.length > 0) {
    timecodes = timecodes.map(tc => ({
      timecode: tc.timecode || tc.time || '',
      scene: tc.scene || tc.visual || tc.description || '',
      dialogue: tc.dialogue || tc.script || tc.text || '',
      note: tc.note || tc.remark || '',
    }));
  }

  if (timecodes.length === 0) {
    const errMsg = '無法解析逐字稿格式';
    await updateStatus('failed', `${errMsg}。原始回傳: ${raw.substring(0, 500)}`);
    return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'failed', error: errMsg } }];
  }

  // === Step 6: 寫回 DB ===
  await updateStatus('completed', raw, timecodes);

  return [{ json: { queue_item_id, title: title || '未知影片', platform, status: 'completed', timecodes_count: timecodes.length } }];

} catch (err) {
  const errorMsg = err.message || String(err);
  try {
    await updateStatus('failed', `處理錯誤: ${errorMsg.substring(0, 500)}`);
  } catch {}
  return [{ json: { queue_item_id, title: title || '未知影片', platform: platform || '', status: 'failed', error: errorMsg.substring(0, 200) } }];
}

// 匯總結果 + 組裝 Slack 訊息
const SLACK_TOKEN = $env.SLACK_BOT_TOKEN || '';
const SLACK_CHANNEL = $env.SLACK_CHANNEL_ID || '';
const SITE_URL = 'https://viral-benchmark.zeabur.app';

const results = $input.all().map(i => i.json);
const completed = results.filter(r => r.status === 'completed');
const failed = results.filter(r => r.status === 'failed');
const total = results.length;

// 組裝 Slack 訊息
let blocks = [];

// 標題
if (failed.length === 0) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*✅ 逐字稿生成完成*\n共 ${total} 支全部成功` }
  });
} else if (completed.length === 0) {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*⚠️ 逐字稿生成失敗*\n共 ${total} 支全部失敗` }
  });
} else {
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*📝 逐字稿生成結果*\n成功 ${completed.length} 支，失敗 ${failed.length} 支（共 ${total} 支）` }
  });
}

// 成功列表
if (completed.length > 0) {
  const successList = completed.map(r => {
    const platformEmoji = r.platform === 'douyin' ? '🎵' : r.platform === 'tiktok' ? '📱' : '📕';
    const shortTitle = (r.title || '').substring(0, 30) || '未知影片';
    return `${platformEmoji} ${shortTitle}（${r.timecodes_count || 0} 段）`;
  }).join('\n');
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*成功：*\n${successList}` }
  });
}

// 失敗列表（帶詳細錯誤）
if (failed.length > 0) {
  const failList = failed.map(r => {
    const platformEmoji = r.platform === 'douyin' ? '🎵' : r.platform === 'tiktok' ? '📱' : '📕';
    const shortTitle = (r.title || '').substring(0, 30) || '未知影片';
    const shortError = (r.error || '未知錯誤').substring(0, 60);
    return `${platformEmoji} ${shortTitle}\n   └ 原因：${shortError}`;
  }).join('\n');
  blocks.push({
    type: 'section',
    text: { type: 'mrkdwn', text: `*失敗：*\n${failList}` }
  });
}

// 按鈕連結
blocks.push({ type: 'divider' });
blocks.push({
  type: 'section',
  text: { type: 'mrkdwn', text: `👉 <${SITE_URL}/shoot-queue|前往拍攝佇列查看>` }
});

// 發送 Slack
if (SLACK_TOKEN && SLACK_CHANNEL) {
  try {
    await fetch('https://slack.com/api/chat.postMessage', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${SLACK_TOKEN}`,
      },
      body: JSON.stringify({
        channel: SLACK_CHANNEL,
        blocks,
        text: `逐字稿生成結果：成功 ${completed.length}，失敗 ${failed.length}`,
      }),
    });
  } catch (e) {
    // Slack 失敗不影響主流程
  }
}

return [{
  json: {
    total,
    completed: completed.length,
    failed: failed.length,
    results,
    slack_sent: !!(SLACK_TOKEN && SLACK_CHANNEL),
  }
}];
